const e={name:"Hasselnöt",icon:"hasselnut",category:"frukt",family:"Björkväxter",familyLatin:"Betulaceae",perennial:!0,lifespan:"40-80 år (uppstammad), 1000+ år (buske via rotskott)",difficulty:"Enkel",difficultyWhy:"Hasseln är ursprunglig i Sverige och sköter sig i princip själv. De storfruktiga odlingssorterna kräver lite mer uppmärksamhet - framförallt en pollineringspartner och skydd mot nötvivlar. Men jämfört med andra fruktträd är hasseln förbluffande anspråkslös.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:null},days:"Skörd år 3-5",spacing:"3-5 m",spacingNote:"Buskform: 3-4 m. Uppstammad: 4-5 m. Tänk på att du behöver minst två sorter för pollinering!",rowSpacing:"4-5 m",depth:"Rotklumpens djup",depthNote:"Plantera på samma djup som plantan stått. Hasseln har ett relativt grunt rotsystem.",ph:{min:5.5,max:7.5,ideal:6},optimalConditions:{sun:{level:"Sol-halvskugga",icon:"sun",detail:"Hasseln trivs i sol till halvskugga - den växer naturligt i skogsbryn. Men för god nötsättning behöver den rejält med sol. I djup skugga blommar den men nötterna uteblir."},temperature:{min:-30,max:35,ideal:"15-25°C",detail:"Extremt härdig - vilda hasslar tål ner mot -30°C. Men hängen (hanblommorna) som slår ut redan i januari-februari tål bara några minusgrader. Kalla vintrar ger dålig pollinering."},wind:{level:"Vindexponerad OK",detail:"Hasseln är vindpollinerad - den BEHÖVER lite vind! Men allt för utsatt läge torkar ut hängena. En lagom skyddad men luftig plats är perfekt."}},watering:{need:"Medel",icon:"water",summary:"Hasseln har ett relativt grunt rotsystem och saknar vaxskikt på bladen - den torkar därför ut lättare än man tror. Regelbunden vattning vid torka ger märkbart bättre skörd.",phases:[{phase:"Vår (pollinering)",need:"Låg",tip:"Normalt tillräckligt med vinterväta och vårregn. Pollineringen sker mitt i vintern - inget du kan påverka."},{phase:"Sommar (nötutveckling)",need:"Medel",tip:"Vattna vid torka! Kärnan börjar fylla skalet i juni - vattenstress nu ger tomma nötter."},{phase:"Sensommar (mognad)",need:"Medel",tip:"Fortsätt vattna vid behov. Nötterna mognar i september-oktober."},{phase:"Vinter",need:"Ingen",tip:"Busken vilar. Ingen vattning behövs."}],mistakes:["Underskattar vattningsbehovet - hasseln har grunt rotsystem och vaxfria blad","Glömmer att vattna under nötutvecklingen (juni-aug) - ger tomma skal"],tip:"Mulcha ordentligt runt busken - det håller fukt och minskar ogräs. Hasseln gillar ett tjockt lager löv eller flis."},soil:"Hasseln trivs i de flesta jordar men föredrar lätt, väldränerad, mullrik jord. Den tål inte vattensjuk mark - rötterna är ytliga och känsliga för stående vatten.",soilTips:["pH runt 6.0 är optimalt - hasseln gillar svagt sur jord","Blanda in kompost vid plantering","Undvik vattensjuka svackor - rötterna tål inte stående vatten","Mullrik skogsbrynsjord är drömmen"],timeline:{1:[{phase:"Hängen sprider pollen",months:"Feb-mars",icon:"bloom"},{phase:"Pollinering",months:"Feb-april",icon:"bloom"},{phase:"Nötutveckling",months:"Juni-sept",icon:"growth"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Beskärning",months:"Feb-mars",icon:"scissors"},{phase:"Vintervila",months:"Nov-jan",icon:"snowflake"}],4:[{phase:"Hängen sprider pollen",months:"Mars-april",icon:"bloom"},{phase:"Nötutveckling",months:"Juni-sept",icon:"growth"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Beskärning",months:"Mars",icon:"scissors"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],6:[{phase:"Hängen sprider pollen",months:"April",icon:"bloom"},{phase:"Nötutveckling",months:"Juli-sept",icon:"growth"},{phase:"Skörd",months:"Okt",icon:"harvest"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:2,P:1,K:1},{month:"Apr",N:4,P:2,K:1},{month:"Maj",N:6,P:4,K:2},{month:"Jun",N:7,P:5,K:4,label:"Kärnfyllning"},{month:"Jul",N:5,P:4,K:6},{month:"Aug",N:3,P:3,K:7,label:"Mognad"},{month:"Sep",N:1,P:2,K:4}],nutritionTips:[{timing:"Tidig vår (april-maj)",tip:"Ge kompost eller brunnen gödsel runt busken. Gödsla inte efter juli - det försämrar nötkvaliteten."},{timing:"Sommar",tip:"Ingen extra gödsling behövs. Mulcha med löv eller flis för långsam näringsfrisättning."},{timing:"Höst",tip:"Lägg ett tjockt lager löv som vintermulch - det bryts ner och ger perfekt vårstart."}],companions:{good:[{name:"Klöver",icon:"flower",why:"Fixerar kväve och täcker marken under hasselbuskarna. Perfekt marktäckare."},{name:"Vitsippa",icon:"flower",why:"Trivs naturligt under hasselbuskar i svenska skogsbryn. Blommar innan hasseln får blad."},{name:"Ramslök",icon:"herb",why:"Klassisk skogsbrynväxt som trivs i halvskuggan under hasselbuskar. Skörd på våren innan löven skuggar."}],bad:[{name:"Gräsmatta intill stammen",icon:"vegetable",why:"Gräs konkurrerar om vatten och näring. Håll marken runt busken fri med mulch istället."}]},rotation:{avoid:[{name:"Hasselnöt"}],avoidWhy:"Hasseln är inte känslig för trötthetssjuka på samma sätt som stenfrukter. En ny buske trivs bra på de flesta platser.",goodBefore:[{name:"Gröngödsling"},{name:"Gräsmatta"}],goodBeforeWhy:"Mullrik, väletablerad jord ger bäst start.",goodAfter:[{name:"Gröngödsling"}],goodAfterWhy:"Jorden under hasselbuskar är ofta utmärkt - rötterna har byggt upp jordstrukturen."},varieties:[{name:"Nottingham Prolific",zones:[1,2,3,4,5],note:"Medelstor nöt som inte krymper vid torkning - ovanligt! 6-8 nötter per klase. Tunn skal. God smak. Härdig till zon 4-5. Den bästa allroundsorten för svenska förhållanden."},{name:"Cosford",zones:[1,2,3],note:"Tunn skal, tidig pollinerare, nästan självfertil. Mild, söt smak. Krymper något vid torkning. Utmärkt pollineringspartner till andra sorter."},{name:"Jättenöt från Halle",zones:[1,2,3,4],note:"Stor nöt med tjockt skal - svårare för nötvivlar att ta sig in! Resistens mot gallkvalster. Härdig. Bra val om nötvivlar är ett problem i din trädgård."},{name:"Gunslebert",zones:[1,2,3],note:"Kraftig sort med söt, aromatisk smak. God pollinerare. Passar till färsk konsumtion, torkning och bakning."},{name:"Röd Zellernöt",zones:[1,2,3],note:"Bronsröda blad, röd hylsa, söt smak. Tidigt mogen (oktober). Både dekorativ och produktiv - vacker häckväxt."}],problems:[{name:"Nötvivel (Curculio nucum)",symptom:"Tomma nötter med ett litet runt hål. Baggen borrar in i den omogna nöten och lägger ägg. Larven äter kärnan inifrån och gnager sig sedan ut.",fix:"Täck marken under buskarna med fiberduk under sensommaren (hindrar larver att ta sig ner i marken). Välj sorter med tjockt skal (Jättenöt från Halle). Samla upp nedfallna nötter snabbt."},{name:"Nötskrika och ekorre",symptom:"Nötterna försvinner dagarna kring mognad. Nötskrikan och ekorren vet EXAKT när nötterna är klara.",fix:"Skörda lite innan full mognad - nötterna eftermognar. Täta bärnät runt buskarna. Var snabbare än djuren."},{name:"Hasselgallkvalster",symptom:'Svullna, rundade knoppar som inte slår ut på våren ("blinda knoppar"). Minskar skörden.',fix:"Plocka bort svullna knoppar under vintern och förstör dem. Välj resistenta sorter (Jättenöt från Halle). Regelbunden beskärning ger luftig krona."},{name:"Dålig nötsättning",symptom:"Busken blommar och växer fint men ger inga eller tomma nötter.",fix:"Vanligaste orsaken: saknar pollineringspartner! Hasseln är självsteril i praktiken. Plantera minst två olika sorter inom 18 meters avstånd. Kalla vintrar försämrar pollineringen."}],pollination:{selfFertile:!1,description:"Hasseln är vindpollinerad med separata han- och honblommor. Hängena (hanblommorna) sprider pollen redan i januari-mars - mitt i vintern! Honblommorna ser ut som små röda trådar ur knopparna. I praktiken är hasseln självsteril - du behöver minst två olika sorter.",groups:[{name:"Tidig pollinering",varieties:["Cosford","Röd Zellernöt"]},{name:"Mellansäsong",varieties:["Nottingham Prolific","Gunslebert"]},{name:"Sen pollinering",varieties:["Jättenöt från Halle"]},{name:"Universell pollinerare",varieties:["Vild hassel (Corylus avellana)"]}],tip:"Vild hassel fungerar utmärkt som pollinerare! Om du har vild hassel i närheten behöver du kanske bara en odlingssort. Krokhassel (Corylus avellana Contorta) är en dekorativ pollinerare som gör jobbet med stil."},establishment:{description:"Hasseln etablerar sig snabbt och ger de första nötterna redan efter 3-5 år. Den är anspråkslös och tålmodig - perfekt för den som vill ha ett produktivt fruktträd utan drama.",years:[{year:"År 1-2",tasks:["Vattna regelbundet under sommaren","Mulcha ordentligt runt busken","Bestäm form: buskform (naturlig) eller uppstammad","Ta bort oönskade rotskott från första säsongen"]},{year:"År 3-5",tasks:["Första nötterna!","Börja regelbunden beskärning: ta bort gamla stammar (tjockare än 10 cm)","Håll 6-10 huvudstammar i buskform","Kontrollera nötvivelproblem - tomma nötter med hål"]},{year:"År 5+",tasks:["Full skörd: 2-4 kg per buske i goda år","Årlig beskärning: byt ut gamla stammar mot nya skott","Ta bort rotskott som sprider sig utanför önskat område"]}],protection:["Stamskydd mot gnagare, särskilt under snötäcke (sorkar!)","Viltskydd om rådjur finns i området","Nätskydd mot nötskvärka och ekorre under skördesäsongen"],tip:"Hasseln bildar naturligt en flerstammig buske med rotskott. Bestäm tidigt om du vill ha buskform (traditionellt, enklare) eller uppstammad form (prydligare, lättare att skörda under). Ympade buskar på turkisk hassel som grundstam ger ingen rotskottsproduktion."},ripeningGuide:{description:"Hasselnötter mognar från september till november beroende på sort. Hylsan (svepet) gulnar och nöten släpper vid lätt vridning. Skörda strax innan full mognad - nötterna eftermognar och du hinner före djuren.",entries:[{variety:"Cosford",from:"sep",to:"okt",type:"Tidig hasselnöt"},{variety:"Nottingham Prolific",from:"sep",to:"okt",type:"Tidig hasselnöt"},{variety:"Röd Zellernöt",from:"okt",to:"okt",type:"Mellansäsong"},{variety:"Gunslebert",from:"okt",to:"okt",type:"Mellansäsong"},{variety:"Jättenöt från Halle",from:"okt",to:"nov",type:"Sen hasselnöt"}],tip:"Flyteprovet avslöjar allt: lägg nötterna i vatten. Tomma nötter flyter, fulla sjunker. Perfekt sätt att sortera bort nötvivelangrepp!"},goodToKnow:[{icon:"tip",title:"Sveriges egen nöt",text:"Hasseln är en av våra mest underskattade inhemska växter. Den invandrade till Sverige för 9 500 år sedan och växer vilt upp till Dalälven. Att odla hassel är att odla svensk historia.",severity:"tip"},{icon:"warning",title:"Du behöver TVÅ sorter",text:"Den vanligaste orsaken till utebliven skörd: hasseln är självsteril i praktiken. Han- och honblommorna på samma buske mognar vid olika tidpunkter. Plantera alltid minst två olika sorter inom 18 meters avstånd. Vild hassel i närheten fungerar som pollinerare.",severity:"warning"},{icon:"tip",title:"Hängen i januari - vinterns tecken på vår",text:"Hasselhängena som sprider gult pollen redan i januari-februari är ett av årets första vårtecken. Honblommorna är små röda trådar ur knopparna - lätta att missa men oerhört viktiga.",severity:"tip"},{icon:"warning",title:"Nötviveln - den listiga fienden",text:"Hittar du tomma nötter med ett litet runt hål har nötviveln varit framme. Baggen borrar in i den omogna nöten och lägger ägg. Larven äter kärnan och gnager sig sedan ut. Välj tjockskaliga sorter (Jättenöt från Halle) och täck marken med fiberduk under sensommaren.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Hasselbuskar planteras som rotade plantor, helst på hösten. De etablerar sig snabbt och börjar ge nötter efter 3-5 år.",steps:["Gräv en grop dubbelt så bred som rotklumpen","Blanda in kompost i den uppgrävda jorden","Plantera på samma djup som plantan stått","Vattna rikligt efter plantering","Mulcha ordentligt i 1 meters radie","Tänk på att plantera minst TVÅ sorter för pollinering!"],tips:["Höstplantering ger bäst etablering","Plantera sorterna inom 18 meters avstånd för pollinering","Vild hassel i närheten räknas som pollinerare","Krokhassel (Contorta) är en dekorativ pollinerare"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Rotskott / Avläggning",biennial:!1,description:"Hasseln är en av de enklaste buskarna att föröka. Rotskott och avläggare ger genetiskt identiska kloner av moderplantan.",steps:["Rotskott: gräv upp ett rotskott med rötter intakta på tidig vår","Avläggare: böj en låg gren ner till marken, sticka och täck med jord","Ta bort knoppar på den begravda delen av avläggaren","Vattna under sommaren - rötter bildas på 6-12 månader","Separera från moderplantan nästa höst"],isolation:"Vegetativ förökning ger exakta kloner av moderplantan.",storageYears:"Nötter kan sås direkt på hösten för fröförökning",tip:"Rotskott är det enklaste sättet - hasseln producerar dem naturligt. Gräv upp ett skott med rötter och plantera på ny plats. Perfekt för att starta en hassellund!"},storage:{shelfLife:"6-24 månader (torkade)",methods:[{method:"Torkning + torrt förvar",icon:"cellar",duration:"1-2 år",description:"Torka nötterna i ventilerat rum i 4-6 veckor tills vattenhalten sjunkit till 8-10%. Förvara svalt och torrt i nätpåsar. De flesta sorter krymper vid torkning - det är normalt.",best:!0},{method:"Färsk i fuktig sand",icon:"cellar",duration:"3-4 månader",description:"Traditionellt svenskt knep: förvara nötterna i fuktig sand utomhus. Behåller färsk smak och textur till jul. Perfekt för sorter som krymper vid torkning.",best:!1},{method:"Frysning (skalade)",icon:"snowflake",duration:"2+ år",description:"Skala och frys i påsar. Alltid redo för bakning, müsli och snacks.",best:!1}],tips:["Flyteprovet: tomma nötter flyter, fulla sjunker - sortera snabbt","Torka ORDENTLIGT - fuktiga nötter möglar snabbt","Nottingham Prolific är unik: den krymper inte vid torkning","Nötskal komposteras långsamt - krossa eller bränn dem"]},harvestCalc:{minPerSqm:2,maxPerSqm:4,unit:"kg per buske"},pruning:{label:"Beskärning",types:{winter:{name:"Vinterbeskärning (buskform)",when:"Februari-mars (före hängesläpp i söder, efter i norr)",description:"Hasseln bildar naturligt en flerstammig buske. Målet är att hålla busken produktiv genom att regelbundet byta ut gamla stammar mot unga skott.",steps:["Behåll 6-10 huvudstammar av varierande ålder","Såga av stammar tjockare än 10 cm - de är förbi sin bästa tid","Ta bort stammar som växer inåt kronan","Ta bort oönskade rotskott (lämna 2-3 unga som ersättare)","Sikta på en öppen, skålformad buske med ljus i mitten"]},summer:{name:"Sommarbeskärning (brutning)",when:"Juli-augusti",description:"Traditionell metod: bryt (klipp inte!) kraftiga sidoskott till hälften. Det bromsar vegetativ tillväxt och stimulerar fruktknoppar. De brutna skotten hänger kvar och skuggar inte.",steps:["Bryt (inte klipp!) kraftiga sidoskott som är 25+ cm","Bryt till halva längden - skottet hänger kvar men slutar växa","Lämna fruktbärande korta skott i fred","Ta bort brutna skott vid vinterbeskärningen"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Rotskott",description:"Det enklaste sättet. Gräv upp ett rotskott med rötter intakta. Hasseln producerar dem naturligt - perfekt för den som vill starta en hassellund.",icon:"seedling"},{method:"Avläggning",description:"Böj en låg gren till marken och täck med jord. Rötter bildas på 6-12 månader. Separera nästa höst.",icon:"seedling"},{method:"Frösådd",description:"Stratifiera nötter hela vintern i fuktig sand. Så på våren. Ca 10% liknar moderplantan - bra för pollinerare men inte för namnsorter.",icon:"seed"}],tip:"Vill du föröka en namnsort exakt: rotskott eller avläggning. Frösådd ger unika plantor som fungerar utmärkt som pollinerare men inte är identiska med moderplantan."}};export{e as hasselnut};
